package com.knoxhack.echostationfall.progression;
import com.knoxhack.echostationfall.Config; import net.minecraft.nbt.CompoundTag; import net.minecraft.world.entity.player.Player;
public final class SignalPanicState { public static final String ROOT="echostationfall_signal_panic"; private int value; private int lastCueTick; public static SignalPanicState get(Player p){return read(p.getPersistentData().getCompoundOrEmpty(ROOT));} public static void reset(Player p){p.getPersistentData().remove(ROOT);} public int value(){return value;} public boolean high(){return value>=45;} public boolean critical(){return value>=80;} public void gain(Player p,int amount){if(amount<=0)return; double m; try{m=Config.PANIC_GAIN_MULTIPLIER.get();}catch(Exception e){m=1.0D;} value=Math.min(100,value+Math.max(1,(int)Math.round(amount*m))); save(p);} public void decay(Player p,int amount){if(amount>0){value=Math.max(0,value-amount); save(p);}} public void tick(Player p, boolean stable, boolean dampener){int interval; try{interval=Config.PANIC_DECAY_TICKS.get();}catch(Exception e){interval=80;} if(p.tickCount%Math.max(10,interval)==0) decay(p,stable?(dampener?8:4):(dampener?2:0));} public boolean cueReady(Player p){int i; try{i=Config.HALLUCINATION_TICKS.get();}catch(Exception e){i=220;} return high()&&p.tickCount-lastCueTick>=Math.max(20,i);} public void markCue(Player p){lastCueTick=p.tickCount; save(p);} public void save(Player p){p.getPersistentData().put(ROOT,write());} public CompoundTag write(){CompoundTag t=new CompoundTag();t.putInt("value",value);t.putInt("last_cue_tick",lastCueTick);return t;} public static SignalPanicState read(CompoundTag t){SignalPanicState s=new SignalPanicState();s.value=Math.max(0,Math.min(100,t.getIntOr("value",0)));s.lastCueTick=t.getIntOr("last_cue_tick",0);return s;}}
